from guardrails import Guard, OnFailAction
from guardrails.validators import Validator, register_validator, PassResult, FailResult
from typing import Any, Dict, Optional
import re

@register_validator(name="no-placeholder-text", data_type="string")
class NoPlaceholderText(Validator):
    """Blocks outputs that contain unfilled template placeholders like {{name}} or [INSERT]."""

    _PATTERNS = [
        re.compile(r"\{\{[^}]+\}\}"),   # {{ variable }}
        re.compile(r"\[INSERT[^\]]*\]"), # [INSERT SOMETHING]
        re.compile(r"<PLACEHOLDER>"),
    ]

    def validate(self, value: Any, metadata: Dict) -> PassResult | FailResult:
        for pat in self._PATTERNS:
            if pat.search(str(value)):
                return FailResult(
                    error_message=f"Output contains unfilled placeholder: {pat.pattern}",
                    fix_value=pat.sub("", str(value)),  # strip it for FIX action
                )
        return PassResult()


guard = (
    Guard()
    .use(NoPlaceholderText, on="output", on_fail=OnFailAction.FIX)
)

import openai
client = openai.OpenAI()

result = guard(
    client.chat.completions.create,
    model="gpt-4o-mini",
    messages=[{"role": "user", "content": "Write a short greeting for our customer."}],
)
print(result.validated_output)  # placeholders stripped if present
